const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// Load credentials from environment variables
const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;

sgMail.setApiKey(SENDGRID_API_KEY);
const client = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

exports.sendEmailAndSMS = async (event) => {
  const { email, phoneNumber, message } = event;

  try {
    // Send Email
    await sgMail.send({
      to: email,
      from: 'your-email@example.com',
      subject: 'Hello from Twilio and SendGrid!',
      text: message,
    });

    // Send SMS
    await client.messages.create({
      body: message,
      from: '+1234567890', // Replace with your Twilio phone number
      to: phoneNumber,
    });

    return {
      statusCode: 200,
      body: JSON.stringify({ message: 'Email and SMS sent successfully' }),
    };
  } catch (error) {
    console.error(error);
    return {
      statusCode: 500,
      body: JSON.stringify({ error: 'Failed to send email or SMS' }),
    };
  }
};